import type { Metadata } from "next";
import PayrollEditor from "./PayrollEditor";

export const metadata: Metadata = {
  title: "給与明細 編集・確定 | ぐんじょう給与",
  description:
    "従業員1名の月次給与明細を確認・確定する画面。勤怠サマリー、支給／控除の明細編集、課税・社会保険・所得税の計算アシスト、差引支給額の自動計算、年間累計、人事→経理→確定の承認フローと差戻しに対応します。",
};

export default function PayrollPage() {
  return <PayrollEditor />;
}

// Domain model + pure calculation helpers for the 給与明細 (payslip) editor.
// Kept framework-free so the math is trivially testable and the editor stays thin.

export type RunStatus = "calculated" | "reviewing" | "confirmed";

/** 課税区分 — whether an earnings line is subject to income tax. */
export type TaxClass = "taxable" | "non_taxable";

export interface EarningLine {
  id: string;
  /** 項目名 (基本給 / 役職手当 / 通勤手当 …) */
  name: string;
  amount: number;
  taxClass: TaxClass;
}

export interface DeductionLine {
  id: string;
  /** 項目名 (健康保険 / 厚生年金 / 所得税 …) */
  name: string;
  amount: number;
}

export interface Attendance {
  workedDays: number; // 出勤日数
  absentDays: number; // 欠勤
  overtimeHours: number; // 残業時間
  paidLeaveDays: number; // 有給消化
}

export interface YearToDate {
  taxableEarnings: number; // 課税支給累計
  socialInsurance: number; // 社会保険累計
  withholdingTax: number; // 源泉所得税累計
}

export type ApprovalStageState =
  | "pending"
  | "current"
  | "approved"
  | "rejected"
  | "skipped";

export interface ApprovalStage {
  key: "hr" | "finance" | "confirm";
  label: string;
  state: ApprovalStageState;
  actor?: string;
  timestamp?: string;
  comment?: string;
}

export interface Employee {
  name: string;
  code: string; // 社員番号
  department: string; // 部署
}

export interface PayrollRun {
  employee: Employee;
  period: string; // 対象月 e.g. "2026年5月分"
  payDate: string; // 支払日
  status: RunStatus;
  attendance: Attendance;
  earnings: EarningLine[];
  deductions: DeductionLine[];
  ytd: YearToDate;
  approvals: ApprovalStage[];
}

// ---- pure calc ------------------------------------------------------------

export const sum = (xs: number[]): number =>
  xs.reduce((a, b) => a + (Number.isFinite(b) ? b : 0), 0);

export const totalEarnings = (lines: EarningLine[]): number =>
  sum(lines.map((l) => l.amount));

export const totalDeductions = (lines: DeductionLine[]): number =>
  sum(lines.map((l) => l.amount));

/** 課税支給 — taxable earnings only (基準内＋課税手当). */
export const taxableEarnings = (lines: EarningLine[]): number =>
  sum(lines.filter((l) => l.taxClass === "taxable").map((l) => l.amount));

/** 非課税支給 — non-taxable earnings (通勤手当 等). */
export const nonTaxableEarnings = (lines: EarningLine[]): number =>
  sum(lines.filter((l) => l.taxClass === "non_taxable").map((l) => l.amount));

/** 社会保険料合計 — the insurance-class deductions (used for 課税対象額 assist). */
const SOCIAL_INSURANCE_NAMES = ["健康保険", "厚生年金", "雇用保険", "介護保険"];

export const socialInsuranceTotal = (lines: DeductionLine[]): number =>
  sum(
    lines
      .filter((l) => SOCIAL_INSURANCE_NAMES.some((n) => l.name.includes(n)))
      .map((l) => l.amount),
  );

/** 課税対象額 = 課税支給 − 社会保険料 (the base 所得税 is derived from). */
export const taxableBase = (
  earnings: EarningLine[],
  deductions: DeductionLine[],
): number => taxableEarnings(earnings) - socialInsuranceTotal(deductions);

/** 差引支給額 = 支給合計 − 控除合計 */
export const netPay = (
  earnings: EarningLine[],
  deductions: DeductionLine[],
): number => totalEarnings(earnings) - totalDeductions(deductions);

export const isNetNegative = (
  earnings: EarningLine[],
  deductions: DeductionLine[],
): boolean => netPay(earnings, deductions) < 0;

// ---- option lists ---------------------------------------------------------

export const TAX_CLASS_OPTIONS: { value: TaxClass; label: string }[] = [
  { value: "taxable", label: "課税" },
  { value: "non_taxable", label: "非課税" },
];

export const STATUS_LABEL: Record<RunStatus, string> = {
  calculated: "計算済",
  reviewing: "確認中",
  confirmed: "確定",
};

export const DEDUCTION_PRESETS = [
  "健康保険",
  "厚生年金",
  "雇用保険",
  "介護保険",
  "所得税",
  "住民税",
  "その他",
];

let seq = 0;
export const newId = (prefix: string): string => `${prefix}-${++seq}-${Date.now()}`;

// ---- seed (one employee, 2026年5月分) ------------------------------------

export function seedRun(): PayrollRun {
  return {
    employee: { name: "佐藤 美咲", code: "EMP-10428", department: "営業本部 / 第一営業部" },
    period: "2026年5月分",
    payDate: "2026年6月25日",
    status: "reviewing",
    attendance: { workedDays: 20, absentDays: 0, overtimeHours: 12.5, paidLeaveDays: 1 },
    earnings: [
      { id: "e1", name: "基本給", amount: 280000, taxClass: "taxable" },
      { id: "e2", name: "役職手当", amount: 35000, taxClass: "taxable" },
      { id: "e3", name: "残業手当", amount: 28400, taxClass: "taxable" },
      { id: "e4", name: "通勤手当（非課税）", amount: 12000, taxClass: "non_taxable" },
    ],
    deductions: [
      { id: "d1", name: "健康保険", amount: 17200 },
      { id: "d2", name: "厚生年金", amount: 31500 },
      { id: "d3", name: "雇用保険", amount: 2130 },
      { id: "d4", name: "所得税", amount: 7430 },
      { id: "d5", name: "住民税", amount: 18000 },
    ],
    ytd: { taxableEarnings: 1717000, socialInsurance: 254150, withholdingTax: 37150 },
    approvals: [
      {
        key: "hr",
        label: "人事 確認",
        state: "approved",
        actor: "田中 健（人事）",
        timestamp: "2026年6月18日 10:24",
      },
      { key: "finance", label: "経理 承認", state: "current", actor: "経理部" },
      { key: "confirm", label: "確定", state: "pending" },
    ],
  };
}

/** An alternate run with no lines — drives the empty / zero state. */
export function emptyRun(): PayrollRun {
  const r = seedRun();
  return {
    ...r,
    employee: { name: "山田 太郎", code: "EMP-10590", department: "管理本部 / 総務部" },
    status: "calculated",
    earnings: [],
    deductions: [],
    ytd: { taxableEarnings: 0, socialInsurance: 0, withholdingTax: 0 },
    approvals: [
      { key: "hr", label: "人事 確認", state: "current", actor: "人事部" },
      { key: "finance", label: "経理 承認", state: "pending" },
      { key: "confirm", label: "確定", state: "pending" },
    ],
  };
}

"use client";

import * as React from "react";
import {
  Badge,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  Alert,
  AlertTitle,
  AlertDescription,
  Statistic,
  MetadataList,
  Separator,
  EditableDataTable,
  ApprovalSteps,
  NumberInput,
  Input,
  Select,
  Textarea,
  Label,
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
  formatCurrency,
  formatNumber,
  type EditableColumn,
  type ApprovalStep,
  type BadgeProps,
} from "@gunjo/ui";
import {
  IconUserCircle,
  IconCalendarMonth,
  IconCash,
  IconCircleCheck,
  IconClockHour4,
  IconAlertTriangle,
  IconLock,
  IconArrowBackUp,
  IconInfoCircle,
  IconReceipt2,
} from "@tabler/icons-react";
import {
  type PayrollRun,
  type EarningLine,
  type DeductionLine,
  type TaxClass,
  type RunStatus,
  STATUS_LABEL,
  TAX_CLASS_OPTIONS,
  DEDUCTION_PRESETS,
  totalEarnings,
  totalDeductions,
  taxableEarnings,
  nonTaxableEarnings,
  socialInsuranceTotal,
  taxableBase,
  netPay,
  isNetNegative,
  newId,
  seedRun,
  emptyRun,
} from "./payroll-data";

const yen = (n: number, opts?: { signed?: boolean }) =>
  formatCurrency(n, { maximumFractionDigits: 0, ...opts });

const STATUS_BADGE: Record<RunStatus, BadgeProps["variant"]> = {
  calculated: "secondary",
  reviewing: "warning",
  confirmed: "success",
};

const STATUS_ICON: Record<RunStatus, React.ReactNode> = {
  calculated: <IconClockHour4 className="h-3.5 w-3.5" aria-hidden />,
  reviewing: <IconClockHour4 className="h-3.5 w-3.5" aria-hidden />,
  confirmed: <IconCircleCheck className="h-3.5 w-3.5" aria-hidden />,
};

export default function PayrollEditor() {
  const [run, setRun] = React.useState<PayrollRun>(seedRun);
  // Local working copies of the editable line arrays.
  const [earnings, setEarnings] = React.useState<EarningLine[]>(run.earnings);
  const [deductions, setDeductions] = React.useState<DeductionLine[]>(run.deductions);
  const [status, setStatus] = React.useState<RunStatus>(run.status);
  const [approvals, setApprovals] = React.useState(run.approvals);
  const [rejectOpen, setRejectOpen] = React.useState(false);
  const [rejectComment, setRejectComment] = React.useState("");

  const readOnly = status === "confirmed";

  // ---- derived totals (recompute every render — cheap) ----
  const earnTotal = totalEarnings(earnings);
  const dedTotal = totalDeductions(deductions);
  const net = netPay(earnings, deductions);
  const negative = isNetNegative(earnings, deductions);
  const taxable = taxableEarnings(earnings);
  const nonTaxable = nonTaxableEarnings(earnings);
  const social = socialInsuranceTotal(deductions);
  const base = taxableBase(earnings, deductions);
  const isEmpty = earnings.length === 0 && deductions.length === 0;

  // 経理 must have approved before 確定 is allowed.
  const financeApproved = approvals.find((a) => a.key === "finance")?.state === "approved";
  const canFinalize = financeApproved && !readOnly && !negative && !isEmpty;

  // ---- data-set switcher (lets a reviewer see the empty / zero state) ----
  const loadRun = (next: PayrollRun) => {
    setRun(next);
    setEarnings(next.earnings);
    setDeductions(next.deductions);
    setStatus(next.status);
    setApprovals(next.approvals);
  };

  // ---- earnings editing ----
  const patchEarning = (i: number, patch: Partial<EarningLine>) =>
    setEarnings((rows) => rows.map((r, idx) => (idx === i ? { ...r, ...patch } : r)));
  const addEarning = () =>
    setEarnings((rows) => [...rows, { id: newId("e"), name: "", amount: 0, taxClass: "taxable" }]);
  const removeEarning = (i: number) =>
    setEarnings((rows) => rows.filter((_, idx) => idx !== i));

  // ---- deductions editing ----
  const patchDeduction = (i: number, patch: Partial<DeductionLine>) =>
    setDeductions((rows) => rows.map((r, idx) => (idx === i ? { ...r, ...patch } : r)));
  const addDeduction = () =>
    setDeductions((rows) => [...rows, { id: newId("d"), name: "", amount: 0 }]);
  const removeDeduction = (i: number) =>
    setDeductions((rows) => rows.filter((_, idx) => idx !== i));

  // ---- approval actions ----
  const approveFinance = () => {
    setApprovals((rows) =>
      rows.map((a) =>
        a.key === "finance"
          ? { ...a, state: "approved", actor: "鈴木 一郎（経理）", timestamp: nowLabel() }
          : a.key === "confirm"
            ? { ...a, state: "current" }
            : a,
      ),
    );
    setStatus("reviewing");
  };

  const finalize = () => {
    if (!canFinalize) return;
    setApprovals((rows) =>
      rows.map((a) =>
        a.key === "confirm"
          ? { ...a, state: "approved", actor: "鈴木 一郎（経理）", timestamp: nowLabel() }
          : a,
      ),
    );
    setStatus("confirmed");
  };

  const submitReject = () => {
    const comment = rejectComment.trim();
    setApprovals((rows) =>
      rows.map((a) =>
        a.key === "finance"
          ? { ...a, state: "rejected", actor: "鈴木 一郎（経理）", timestamp: nowLabel(), comment }
          : a.key === "confirm"
            ? { ...a, state: "pending" }
            : a,
      ),
    );
    setStatus("calculated");
    setRejectOpen(false);
    setRejectComment("");
  };

  // ---- earnings grid columns ----
  const earningCols: EditableColumn<EarningLine>[] = [
    {
      id: "name",
      header: "支給項目",
      headerLabel: "支給項目",
      cell: (row, ctx) => (
        <Input
          aria-label={ctx.ariaLabel}
          value={row.name}
          disabled={readOnly}
          placeholder="例：基本給"
          onChange={(e) => patchEarning(ctx.rowIndex, { name: e.target.value })}
        />
      ),
    },
    {
      id: "taxClass",
      header: "課税区分",
      headerLabel: "課税区分",
      width: "9rem",
      cell: (row, ctx) => (
        <Select
          aria-label={ctx.ariaLabel}
          value={row.taxClass}
          disabled={readOnly}
          onChange={(e) => patchEarning(ctx.rowIndex, { taxClass: e.target.value as TaxClass })}
        >
          {TAX_CLASS_OPTIONS.map((o) => (
            <option key={o.value} value={o.value}>
              {o.label}
            </option>
          ))}
        </Select>
      ),
    },
    {
      id: "amount",
      header: "金額",
      headerLabel: "金額",
      align: "right",
      width: "11rem",
      minWidth: "9rem",
      cell: (row, ctx) =>
        readOnly ? (
          <span className="block text-right tabular-nums">{yen(row.amount)}</span>
        ) : (
          <NumberInput
            aria-label={`${ctx.ariaLabel}（円）`}
            value={row.amount}
            min={0}
            step={1000}
            className="w-full text-right tabular-nums"
            onValueChange={(v) => patchEarning(ctx.rowIndex, { amount: v })}
          />
        ),
    },
  ];

  // ---- deductions grid columns ----
  const deductionCols: EditableColumn<DeductionLine>[] = [
    {
      id: "name",
      header: "控除項目",
      headerLabel: "控除項目",
      cell: (row, ctx) => (
        <Input
          aria-label={ctx.ariaLabel}
          value={row.name}
          disabled={readOnly}
          list="deduction-presets"
          placeholder="例：健康保険"
          onChange={(e) => patchDeduction(ctx.rowIndex, { name: e.target.value })}
        />
      ),
    },
    {
      id: "amount",
      header: "金額",
      headerLabel: "金額",
      align: "right",
      width: "11rem",
      minWidth: "9rem",
      cell: (row, ctx) =>
        readOnly ? (
          <span className="block text-right tabular-nums">{yen(row.amount)}</span>
        ) : (
          <NumberInput
            aria-label={`${ctx.ariaLabel}（円）`}
            value={row.amount}
            min={0}
            step={100}
            className="w-full text-right tabular-nums"
            onValueChange={(v) => patchDeduction(ctx.rowIndex, { amount: v })}
          />
        ),
    },
  ];

  const earningError = (row: EarningLine): string | undefined =>
    row.name.trim() === "" && row.amount > 0 ? "項目名を入力してください" : undefined;
  const deductionError = (row: DeductionLine): string | undefined =>
    row.name.trim() === "" && row.amount > 0 ? "項目名を入力してください" : undefined;

  // ---- approval steps (mapped to ApprovalSteps) ----
  const approvalSteps: ApprovalStep[] = approvals.map((a) => ({
    label: a.label,
    state: a.state,
    actor: a.actor,
    timestamp: a.timestamp,
    comment: a.comment,
  }));

  return (
    <main className="mx-auto w-full max-w-5xl px-4 py-8 sm:px-6 lg:px-8">
      {/* Skip-free heading: single h1. */}
      <header className="flex flex-col gap-4">
        <div className="flex flex-wrap items-start justify-between gap-3">
          <div className="flex flex-col gap-1">
            <p className="text-xs font-medium uppercase tracking-wide text-muted-foreground">
              給与明細
            </p>
            <h1 className="text-2xl font-bold tracking-tight">給与明細 編集・確定</h1>
          </div>
          <StatusBadge status={status} />
        </div>

        {/* dataset switcher — lets a reviewer flip to the zero / empty state */}
        <div className="flex flex-wrap items-center gap-2" role="group" aria-label="表示する従業員を切り替え">
          <span className="text-xs text-muted-foreground">表示データ:</span>
          <Button
            type="button"
            size="sm"
            variant={run.employee.code === "EMP-10428" ? "secondary" : "ghost"}
            onClick={() => loadRun(seedRun())}
          >
            佐藤 美咲（通常）
          </Button>
          <Button
            type="button"
            size="sm"
            variant={run.employee.code === "EMP-10590" ? "secondary" : "ghost"}
            onClick={() => loadRun(emptyRun())}
          >
            山田 太郎（未入力）
          </Button>
        </div>
      </header>

      {/* 対象ヘッダ */}
      <Card className="mt-6">
        <CardContent className="pt-6">
          <MetadataList
            layout="horizontal"
            items={[
              {
                label: "従業員",
                value: run.employee.name,
                description: `${run.employee.code} ・ ${run.employee.department}`,
                icon: <IconUserCircle className="h-4 w-4" aria-hidden />,
              },
              {
                label: "対象月",
                value: run.period,
                icon: <IconCalendarMonth className="h-4 w-4" aria-hidden />,
              },
              {
                label: "支払日",
                value: run.payDate,
                icon: <IconCash className="h-4 w-4" aria-hidden />,
              },
              {
                label: "ステータス",
                value: STATUS_LABEL[status],
                icon: STATUS_ICON[status],
              },
            ]}
          />
        </CardContent>
      </Card>

      {readOnly ? (
        <Alert variant="success" className="mt-6">
          <IconLock className="h-4 w-4" aria-hidden />
          <AlertTitle as="h2">この給与明細は確定済みです</AlertTitle>
          <AlertDescription>
            確定後の明細は読み取り専用です。修正が必要な場合は差戻し後に再計算してください。
          </AlertDescription>
        </Alert>
      ) : null}

      {/* 勤怠 KPI */}
      <section aria-labelledby="attendance-h" className="mt-8">
        <h2 id="attendance-h" className="mb-3 text-lg font-semibold">
          勤怠サマリー
        </h2>
        <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
          <Statistic label="出勤日数" value={`${run.attendance.workedDays} 日`} />
          <Statistic
            label="欠勤"
            value={`${run.attendance.absentDays} 日`}
            tone={run.attendance.absentDays > 0 ? "negative" : "neutral"}
          />
          <Statistic
            label="残業時間"
            value={`${formatNumber(run.attendance.overtimeHours, { maximumFractionDigits: 1 })} h`}
          />
          <Statistic label="有給消化" value={`${run.attendance.paidLeaveDays} 日`} />
        </div>
      </section>

      <datalist id="deduction-presets">
        {DEDUCTION_PRESETS.map((p) => (
          <option key={p} value={p} />
        ))}
      </datalist>

      {/* 支給 */}
      <section aria-labelledby="earnings-h" className="mt-8">
        <h2 id="earnings-h" className="mb-3 text-lg font-semibold">
          支給
        </h2>
        <EditableDataTable
          rows={earnings}
          columns={earningCols}
          getRowId={(row) => row.id}
          onAddRow={readOnly ? undefined : addEarning}
          onRemoveRow={readOnly ? undefined : removeEarning}
          getRowError={earningError}
          rowLabel={(i) => `支給 ${i + 1}行目`}
          caption="支給項目ごとの金額。課税／非課税を選択でき、合計は自動計算されます。"
          labels={{
            addRow: "支給項目を追加",
            removeRow: (i) => `支給 ${i + 1}行目を削除`,
            empty: "支給項目がありません。「支給項目を追加」から入力してください。",
          }}
          footer={
            <TotalRow
              label="支給合計"
              value={yen(earnTotal)}
              sub={`課税 ${yen(taxable)} ／ 非課税 ${yen(nonTaxable)}`}
            />
          }
        />
      </section>

      {/* 控除 */}
      <section aria-labelledby="deductions-h" className="mt-8">
        <h2 id="deductions-h" className="mb-3 text-lg font-semibold">
          控除
        </h2>
        <EditableDataTable
          rows={deductions}
          columns={deductionCols}
          getRowId={(row) => row.id}
          onAddRow={readOnly ? undefined : addDeduction}
          onRemoveRow={readOnly ? undefined : removeDeduction}
          getRowError={deductionError}
          rowLabel={(i) => `控除 ${i + 1}行目`}
          caption="社会保険・税・その他の控除。合計は自動計算されます。"
          labels={{
            addRow: "控除項目を追加",
            removeRow: (i) => `控除 ${i + 1}行目を削除`,
            empty: "控除項目がありません。「控除項目を追加」から入力してください。",
          }}
          footer={
            <TotalRow
              label="控除合計"
              value={yen(dedTotal)}
              sub={`うち社会保険 ${yen(social)}`}
            />
          }
        />
      </section>

      {/* 差引支給額 + 税計算アシスト */}
      <section aria-labelledby="net-h" className="mt-8">
        <h2 id="net-h" className="mb-3 text-lg font-semibold">
          差引支給額・税計算
        </h2>
        <div className="grid gap-4 lg:grid-cols-[1.1fr_1fr]">
          {/* net pay */}
          <Card aria-live="polite">
            <CardHeader>
              <CardTitle as="h3" className="text-base">
                差引支給額（手取り）
              </CardTitle>
            </CardHeader>
            <CardContent className="flex flex-col gap-3">
              <p
                className={`text-3xl font-bold tabular-nums ${
                  negative ? "text-destructive" : "text-foreground"
                }`}
              >
                {yen(net, { signed: negative })}
              </p>
              <Separator />
              <dl className="grid grid-cols-2 gap-y-1 text-sm">
                <dt className="text-muted-foreground">支給合計</dt>
                <dd className="text-right tabular-nums">{yen(earnTotal)}</dd>
                <dt className="text-muted-foreground">控除合計</dt>
                <dd className="text-right tabular-nums">− {yen(dedTotal)}</dd>
              </dl>
              {negative ? (
                <Alert variant="destructive">
                  <IconAlertTriangle className="h-4 w-4" aria-hidden />
                  <AlertTitle as="h4">差引支給額がマイナスです</AlertTitle>
                  <AlertDescription>
                    控除合計（{yen(dedTotal)}）が支給合計（{yen(earnTotal)}
                    ）を上回っています。確定する前に金額を見直してください。
                  </AlertDescription>
                </Alert>
              ) : null}
            </CardContent>
          </Card>

          {/* tax calc assist */}
          <Alert variant="info" className="h-fit">
            <IconInfoCircle className="h-4 w-4" aria-hidden />
            <AlertTitle as="h3">社会保険・税の計算アシスト</AlertTitle>
            <AlertDescription>
              <dl className="mt-2 grid grid-cols-[1fr_auto] gap-x-4 gap-y-1.5 text-sm">
                <dt>課税支給</dt>
                <dd className="text-right tabular-nums">{yen(taxable)}</dd>
                <dt>非課税支給（通勤手当 等）</dt>
                <dd className="text-right tabular-nums">{yen(nonTaxable)}</dd>
                <dt>社会保険料合計</dt>
                <dd className="text-right tabular-nums">− {yen(social)}</dd>
                <dt className="font-medium text-foreground">課税対象額</dt>
                <dd className="text-right font-medium tabular-nums text-foreground">
                  {yen(base)}
                </dd>
              </dl>
              <p className="mt-3 text-xs">
                所得税は <strong>課税対象額（{yen(base)}）</strong>
                を基準に、源泉徴収税額表（月額・甲欄）から算出しています。
              </p>
            </AlertDescription>
          </Alert>
        </div>
      </section>

      {/* 年間累計 */}
      <section aria-labelledby="ytd-h" className="mt-8">
        <h2 id="ytd-h" className="mb-3 text-lg font-semibold">
          年間累計（{run.period.replace(/(\d+)年.*/, "$1年度")}）
        </h2>
        <div className="grid grid-cols-1 gap-3 sm:grid-cols-3">
          <Statistic
            label="課税支給累計"
            value={yen(run.ytd.taxableEarnings)}
            hint="今年度の課税対象支給"
          />
          <Statistic
            label="社会保険累計"
            value={yen(run.ytd.socialInsurance)}
            hint="健保・年金・雇用・介護"
          />
          <Statistic
            label="源泉所得税累計"
            value={yen(run.ytd.withholdingTax)}
            hint="今年度の源泉徴収"
          />
        </div>
      </section>

      {/* 承認・確定フロー */}
      <section aria-labelledby="approval-h" className="mt-8">
        <h2 id="approval-h" className="mb-3 text-lg font-semibold">
          承認・確定フロー
        </h2>
        <Card>
          <CardContent className="pt-6">
            <ApprovalSteps
              steps={approvalSteps}
              stateLabels={{
                pending: "未着手",
                current: "確認中",
                approved: "承認済",
                rejected: "差戻し",
                skipped: "スキップ",
              }}
            />

            <Separator className="my-5" />

            {/* finalize blocked reason — always reachable as text */}
            {!readOnly && !canFinalize ? (
              <p
                id="finalize-reason"
                className="mb-3 flex items-start gap-2 text-sm text-muted-foreground"
              >
                <IconInfoCircle className="mt-0.5 h-4 w-4 shrink-0" aria-hidden />
                <span>
                  {isEmpty
                    ? "支給・控除の明細が未入力のため確定できません。"
                    : negative
                      ? "差引支給額がマイナスのため確定できません。金額を見直してください。"
                      : !financeApproved
                        ? "経理の承認が完了するまで確定できません。"
                        : "確定できません。"}
                </span>
              </p>
            ) : null}

            <div className="flex flex-wrap gap-2">
              {!readOnly && !financeApproved ? (
                <Button type="button" variant="primary" onClick={approveFinance} disabled={isEmpty || negative}>
                  <IconCircleCheck className="h-4 w-4" aria-hidden />
                  経理として承認
                </Button>
              ) : null}

              {!readOnly ? (
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => setRejectOpen(true)}
                >
                  <IconArrowBackUp className="h-4 w-4" aria-hidden />
                  差戻し
                </Button>
              ) : null}

              {!readOnly ? (
                <Button
                  type="button"
                  variant="success"
                  onClick={finalize}
                  disabled={!canFinalize}
                  aria-describedby={!canFinalize ? "finalize-reason" : undefined}
                >
                  <IconLock className="h-4 w-4" aria-hidden />
                  この明細を確定する
                </Button>
              ) : (
                <Button type="button" variant="ghost" onClick={() => loadRun({ ...run, status: "reviewing", approvals })} disabled>
                  <IconReceipt2 className="h-4 w-4" aria-hidden />
                  確定済み
                </Button>
              )}
            </div>
          </CardContent>
        </Card>
      </section>

      {/* 差戻しコメント modal */}
      <Dialog open={rejectOpen} onOpenChange={setRejectOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>給与明細を差戻し</DialogTitle>
            <DialogDescription>
              差戻し理由を入力してください。担当者に通知され、明細は「計算済」に戻ります。
            </DialogDescription>
          </DialogHeader>
          <div className="flex flex-col gap-2">
            <Label htmlFor="reject-comment">差戻しコメント</Label>
            <Textarea
              id="reject-comment"
              rows={3}
              value={rejectComment}
              placeholder="例：残業手当の根拠を確認してください。"
              onChange={(e) => setRejectComment(e.target.value)}
            />
          </div>
          <DialogFooter>
            <Button type="button" variant="ghost" onClick={() => setRejectOpen(false)}>
              キャンセル
            </Button>
            <Button
              type="button"
              variant="destructive"
              onClick={submitReject}
              disabled={rejectComment.trim() === ""}
            >
              差戻す
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </main>
  );
}

function nowLabel(): string {
  const d = new Date();
  return `${d.getFullYear()}年${d.getMonth() + 1}月${d.getDate()}日 ${String(
    d.getHours(),
  ).padStart(2, "0")}:${String(d.getMinutes()).padStart(2, "0")}`;
}

function StatusBadge({ status }: { status: RunStatus }) {
  return (
    <Badge variant={STATUS_BADGE[status]} className="gap-1.5 px-3 py-1 text-sm">
      {STATUS_ICON[status]}
      <span>{STATUS_LABEL[status]}</span>
    </Badge>
  );
}

/** Footer total row — flexes label left / figure right so it still reads as a total. */
function TotalRow({
  label,
  value,
  sub,
}: {
  label: string;
  value: string;
  sub?: string;
}) {
  return (
    <div className="flex flex-wrap items-baseline justify-between gap-x-4 gap-y-1">
      <span className="flex flex-col">
        <span className="font-semibold">{label}</span>
        {sub ? <span className="text-xs font-normal text-muted-foreground">{sub}</span> : null}
      </span>
      <span className="text-lg font-bold tabular-nums">{value}</span>
    </div>
  );
}
